class InputValidator:
    """Validates and sanitizes all client input server-side."""

    # Strict allowlists for input types
    VALID_ACTIONS = frozenset({
        'move', 'shoot', 'reload', 'use_item', 'ping', 'spectate'
    })

    MAX_INPUT_RATE = 128  # Max inputs per second (tick rate)
    MAX_MOVE_SPEED = 12.0  # Max units per tick
    MAX_ROTATION_SPEED = 720.0  # Max degrees per second
    MAX_MESSAGE_SIZE = 2048  # bytes
    MAX_DISPLAY_NAME_LENGTH = 24
    ALLOWED_NAME_CHARS = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_-')

    @staticmethod
    def validate_display_name(name: str) -> Optional[str]:
        if not isinstance(name, str):
            return None
        name = name.strip()
        if not 1 <= len(name) <= InputValidator.MAX_DISPLAY_NAME_LENGTH:
            return None
        if not all(c in InputValidator.ALLOWED_NAME_CHARS for c in name):
            return None
        return name

    @staticmethod
    def validate_action(action: str) -> Optional[str]:
        if action in InputValidator.VALID_ACTIONS:
            return action
        return None

    @staticmethod
    def validate_movement(dx: float, dz: float) -> Tuple[float, float]:
        """Clamp movement input to valid range [-1, 1]."""
        try:
            dx = max(-1.0, min(1.0, float(dx)))
            dz = max(-1.0, min(1.0, float(dz)))
            # Normalize diagonal movement
            magnitude = math.sqrt(dx * dx + dz * dz)
            if magnitude > 1.0:
                dx /= magnitude
                dz /= magnitude
            return dx, dz
        except (ValueError, TypeError):
            return 0.0, 0.0

    @staticmethod
    def validate_rotation(rotation: float) -> float:
        try:
            rotation = float(rotation)
            if math.isnan(rotation) or math.isinf(rotation):
                return 0.0
            return rotation % 360.0
        except (ValueError, TypeError):
            return 0.0

    @staticmethod
    def validate_sequence_number(seq: int, last_seq: int) -> Optional[int]:
        try:
            seq = int(seq)
            if seq <= last_seq:
                return None  # Replay or out-of-order
            if seq > last_seq + 1000:
                return None  # Suspicious gap
            return seq
        except (ValueError, TypeError):
            return None


class VisibilitySystem:
    """
    SERVER-SIDE visibility culling - the core anti-wallhack defense.
    
    SECURITY CRITICAL: This system determines what information each client receives.
    Players only receive positions of other players that are legitimately visible.
    This prevents wallhacks because the client never receives hidden player data.
    """

    # Maximum distance at which any player can be "seen"
    MAX_VISIBILITY_DISTANCE = 200.0
    # Distance for guaranteed visibility (footstep sounds, etc.)
    AUDIO_PROXIMITY_DISTANCE = 30.0
    # Field of view doesn't matter for server culling - we use 360 degree
    # awareness with distance + LoS checks to be fair but secure
    # We add a small buffer zone to prevent pop-in
    VISIBILITY_BUFFER = 15.0

    def __init__(self, game_map: GameMap):
        self.game_map = game_map
        # Spatial hash grid for efficient proximity queries
        self.grid_cell_size = 50.0
        self.spatial_grid: Dict[Tuple[int, int], Set[str]] = defaultdict(set)

    def _get_grid_cell(self, pos: Vector3) -> Tuple[int, int]:
        return (
            int(pos.x // self.grid_cell_size),
            int(pos.z // self.grid_cell_size)
        )

    def update_spatial_grid(self, players: Dict[str, Player]):
        """Rebuild spatial hash grid each tick."""
        self.spatial_grid.clear()
        for pid, player in players.items():
            if player.state == PlayerState.ALIVE:
                cell = self._get_grid_cell(player.position)
                self.spatial_grid[cell].add(pid)

    def _get_nearby_cells(self, pos: Vector3, radius: float) -> List[Tuple[int, int]]:
        """Get all grid cells within radius of position."""
        cells = []
        center_cell = self._get_grid_cell(pos)
        cell_radius = int(math.ceil(radius / self.grid_cell_size)) + 1
        for dx in range(-cell_radius, cell_radius + 1):
            for dz in range(-cell_radius, cell_radius + 1):
                cells.append((center_cell[0] + dx, center_cell[1] + dz))
        return cells

    def _line_of_sight_check(self, from_pos: Vector3, to_pos: Vector3) -> bool:
        """
        Ray-cast between two positions to check for obstacle occlusion.
        Uses AABB intersection for each obstacle.
        """
        dx = to_pos.x - from_pos.x
        dy = to_pos.y - from_pos.y
        dz = to_pos.z - from_pos.z
        distance = math.sqrt(dx * dx + dy * dy + dz * dz)

        if distance < 0.001:
            return True

        # Normalize direction
        inv_dist = 1.0 / distance
        dir_x = dx * inv_dist
        dir_y = dy * inv_dist
        dir_z = dz * inv_dist

        for obstacle in self.game_map.obstacles:
            if not obstacle.is_opaque:
                continue
            if self._ray_intersects_aabb(
                from_pos, dir_x, dir_y, dir_z, distance, obstacle
            ):
                return False

        return True

    def _ray_intersects_aabb(
        self, origin: Vector3, dir_x: float, dir_y: float, dir_z: float,
        max_dist: float, obstacle: Obstacle
    ) -> bool:
        """Slab method for ray-AABB intersection."""
        t_min = 0.0
        t_max = max_dist

        for axis in range(3):
            if axis == 0:
                o = origin.x; d = dir_x
                box_min = obstacle.min_point.x; box_max = obstacle.max_point.x
            elif axis == 1:
                o = origin.y; d = dir_y
                box_min = obstacle.min_point.y; box_max = obstacle.max_point.y
            else:
                o = origin.z; d = dir_z
                box_min = obstacle.min_point.z; box_max = obstacle.max_point.z

            if abs(d) < 1e-8:
                if o < box_min or o > box_max:
                    return False
            else:
                inv_d = 1.0 / d
                t1 = (box_min - o) * inv_d
                t2 = (box_max - o) * inv_d
                if t1 > t2:
                    t1, t2 = t2, t1
                t_min = max(t_min, t1)
                t_max = min(t_max, t2)
                if t_min > t_max:
                    return False

        return True

    def compute_visible_players(
        self, observer: Player, all_players: Dict[str, Player]
    ) -> Dict[str, dict]:
        """
        SECURITY CRITICAL: Compute which players are visible to the observer.
        
        Only returns data for players that the observer can legitimately see.
        This is the primary defense against wallhacks.
        
        Visibility rules:
        1. Teammates are always visible (minimap, etc.)
        2. Players within audio proximity are revealed (position only, no details)
        3. Players within max distance AND with line-of-sight are fully visible
        4. All other players are NOT sent to the client at all
        """
        visible = {}

        if observer.state == PlayerState.ELIMINATED:
            return visible

        # Spectators see everything (they're already eliminated)
        if observer.state == PlayerState.SPECTATING:
            for pid, player in all_players.items():
                if player.state == PlayerState.ALIVE:
                    visible[pid] = self._full_player_data(player)
            return visible

        nearby_cells = self._get_nearby_cells(
            observer.position,
            self.MAX_VISIBILITY_DISTANCE + self.VISIBILITY_BUFFER
        )

        candidate_pids: Set[str] = set()
        for cell in nearby_cells:
            candidate_pids.update(self.spatial_grid.get(cell, set()))

        for pid in candidate_pids:
            if pid == observer.player_id:
                continue

            player = all_players.get(pid)
            if not player or player.state != PlayerState.ALIVE:
                continue

            distance = observer.position.distance_to(player.position)

            # Rule 1: Teammates always visible
            if (observer.team_id and player.team_id and
                    observer.team_id == player.team_id):
                visible[pid] = self._full_player_data(player)
                continue

            # Rule 2: Audio proximity - reveal position only (no health/shield)
            if distance <= self.AUDIO_PROXIMITY_DISTANCE:
                visible[pid] = self._proximity_player_data(player)
                continue

            # Rule 3: Distance + Line of sight check
            if distance <= self.MAX_VISIBILITY_DISTANCE:
                if self._line_of_sight_check(observer.position, player.position):
                    visible[pid] = self._full_player_data(player)
                    continue

                # Buffer zone: if player was recently visible, keep sending
                # for a short grace period to prevent pop-in
                # (This is handled by the game state's recent_visibility tracking)

        return visible

    def _full_player_data(self, player: Player) -> dict:
        """Full player data for visible enemies."""
        return {
            'position': player.position.to_dict(),
            'rotation': player.rotation,
            'velocity': player.velocity.to_dict(),
            'health': player.health,
            'shield': player.shield,
            'state': player.state.name,
            'display_name': player.display_name,
        }

    def _proximity_player_data(self, player: Player) -> dict:
        """Limited data for audio-proximity detection (no health/shield)."""
        return {
            'position': player.position.to_dict(),
            'rotation': player.rotation,
            'velocity': player.velocity.to_dict(),
            'state': player.state.name,
            'proximity_only': True,
        }


class AntiCheatValidator:
    """Server-side anti-cheat validation for player actions."""

    MAX_SPEED = 12.0  # units per tick
    MAX_SPEED_SPRINT = 18.0
    TELEPORT_THRESHOLD = 50.0
    MAX_FIRE_RATE = 0.05  # seconds between shots (1200 RPM max)
    MAX_VIOLATIONS_BEFORE_KICK = 10

    def __init__(self):
        self.violation_counts: Dict[str, int] = defaultdict(int)

    def validate_movement(
        self, player: Player, new_position: Vector3,
        delta_time: float, game_map: GameMap
    ) -> Tuple[bool, Vector3]:
        """
        Validate player movement server-side.
        Returns (is_valid, corrected_position).
        """
        if delta_time <= 0:
            return False, player.position

        distance = player.last_validated_position.distance_to(new_position)
        max_allowed = self.MAX_SPEED_SPRINT * delta_time * 1.1  # 10% tolerance for latency

        # Check for teleportation
        if distance > self.TELEPORT_THRESHOLD:
            logger.warning(
                f"Player {player.player_id[:8]}... teleport detected: "
                f"distance={distance:.1f}"
            )
            self.violation_counts[player.player_id] += 3
            return False, player.last_validated_position

        # Check speed
        if distance > max_allowed:
            self.violation_counts[player.player_id] += 1
            # Clamp to max allowed distance in the movement direction
            if distance > 0:
                ratio = max_allowed / distance
                corrected = Vector3(
                    player.last_validated_position.x + (new_position.x - player.last_validated_position.x) * ratio,
                    player.last_validated_position.y + (new_position.y - player.last_validated_position.y) * ratio,
                    player.last_validated_position.z + (new_position.z - player.last_validated_position.z) * ratio,
                )
                if game_map.is_within_bounds(corrected):
                    return True, corrected
            return False, player.last_validated_position

        # Check map bounds
        if not game_map.is_within_bounds(new_position):
            return False, player.last_validated_position

        return True, new_position

    def validate_shot(self, player: Player, current_time: float) -> bool:
        """Validate fire rate."""
        if current_time - player.last_shot_time < self.MAX_FIRE_RATE:
            self.violation_counts[player.player_id] += 1
            return False
        return True

    def should_kick(self, player_id: str) -> bool:
        return self.violation_counts[player_id] >= self.MAX_VIOLATIONS_BEFORE_KICK


class TokenManager:
    """Secure session token management."""

    def __init__(self):
        # In production, use a proper secret management system (e.g., HashiCorp Vault)
        self._signing_key = secrets.token_bytes(64)
        self._active_tokens: Dict[str, Tuple[str, float]] = {}  # token -> (player_id, expiry)

    def generate_session_token(self, player_id: str) -> str:
        """Generate a cryptographically secure session token."""
        token = secrets.token_urlsafe(48)
        expiry = time.time() + 3600  # 1 hour
        # Store hash of token, not the token itself
        token_hash = self._hash_token(token)
        self._active_tokens[token_hash] = (player_id, expiry)
        return token

    def validate_token(self, token: str) -> Optional[str]:
        """Validate a session token. Returns player_id or None."""
        if not isinstance(token, str) or len(token) > 128:
            return None
        token_hash = self._hash_token(token)
        entry = self._active_tokens.get(token_hash)
        if not entry:
            return None
        player_id, expiry = entry
        if time.time() > expiry:
            del self._active_tokens[token_hash]
            return None
        return player_id

    def revoke_token(self, token: str):
        token_hash = self._hash_token(token)
        self._active_tokens.pop(token_hash, None)

    def _hash_token(self, token: str) -> str:
        return hmac.new(self._signing_key, token.encode(), hashlib.sha256).hexdigest()

    def cleanup_expired(self):
        now = time.time()
        expired = [k for k, (_, exp) in self._active_tokens.items() if now > exp]
        for k in expired:
            del self._active_tokens[k]


class RateLimiter:
    """Per-client rate limiting to prevent DoS."""

    def __init__(self, max_requests: int = 128, window_seconds: float = 1.0):
        self.max_requests = max_requests
        self.window = window_seconds
        self._request_times: Dict[str, List[float]] = defaultdict(list)

    def check(self, client_id: str) -> bool:
        now = time.time()
        times = self._request_times[client_id]
        # Remove old entries
        cutoff = now - self.window
        self._request_times[client_id] = [t for t in times if t > cutoff]
        if len(self._request_times[client_id]) >= self.max_requests:
            return False
        self._request_times[client_id].append(now)
        return True

    def cleanup(self, client_id: str):
        self._request_times.pop(client_id, None)


