    def _create_ssl_context(self) -> Optional[ssl.SSLContext]:
        """Create SSL context for transport security."""
        cert_path = pathlib.Path("server.crt")
        key_path = pathlib.Path("server.key")

        if cert_path.exists() and key_path.exists():
            ctx = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
            ctx.minimum_version = ssl.TLSVersion.TLSv1_2
            ctx.load_cert_chain(str(cert_path), str(key_path))
            ctx.set_ciphers('ECDHE+AESGCM:ECDHE+CHACHA20:DHE+AESGCM')
            logger.info("TLS enabled for transport security")
            return ctx
        else:
            logger.warning(
                "TLS certificates not found (server.crt, server.key). "
                "Running WITHOUT transport encryption. "
                "Generate certs for production use!"
            )
            return None

    async def start(self):
        """Start the game server."""
        ssl_ctx = self._create_ssl_context()
        server = await asyncio.start_server(
            self._handle_client,
            self.host,
            self.port,
            ssl=ssl_ctx,
        )
        self.running = True
        logger.info(f"Battle Royale server started on {self.host}:{self.port}")
        logger.info(f"Tick rate: {self.TICK_RATE} Hz, Max players: {self.MAX_PLAYERS}")
        logger.info("Server-side visibility culling ENABLED (anti-wallhack)")

        async with server:
            game_loop_task = asyncio.create_task(self._game_loop())
            cleanup_task = asyncio.create_task(self._cleanup_loop())
            try:
                await server.serve_forever()
            finally:
                self.running = False
                game_loop_task.cancel()
                cleanup_task.cancel()

    async def _handle_client(
        self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter
    ):
        """Handle a new client connection."""
        addr = writer.get_extra_info('peername')
        address_str = f"{addr[0]}:{addr[1]}" if addr else "unknown"
        logger.info(f"New connection from {address_str}")

        connection: Optional[ClientConnection] = None
        player_id: Optional[str] = None

        try:
            # Authentication phase
            connection, player_id = await self._authenticate_client(
                reader, writer, address_str
            )
            if not connection:
                return

            # Send initial game state (only what this player should see)
            await self._send_initial_state(connection)

            # Main client message loop
            await self._client_message_loop(connection)

        except asyncio.CancelledError:
            pass
        except ConnectionResetError:
            logger.info(f"Connection reset: {address_str}")
        except Exception as e:
            logger.error(f"Error handling client {address_str}: {type(e).__name__}")
        finally:
            if player_id:
                await self._disconnect_player(player_id)
            try:
                writer.close()
                await writer.wait_closed()
            except Exception:
                pass

