            # Check player limit
            async with self._lock:
                alive_count = sum(
                    1 for p in self.players.values()
                    if p.state in (PlayerState.ALIVE, PlayerState.DOWNED)
                )
                if alive_count >= self.MAX_PLAYERS:
                    await self._send_error(writer, "Server full")
                    return None, None

            # In production, validate against auth service here
            # For now, generate a player ID and session token
